var currentCanvasFormat = 'diagram';
var CANVAS_FORMATS = ['diagram', 'unicode', 'ascii'];

// The preview shows one representation of the source at a time. Switching format
// swaps the canvas view, gates the zoom controls to the diagram, and retargets
// the copy button — so the same diagram is never on screen twice.
function selectCanvasFormat(fmt) {
  if (CANVAS_FORMATS.indexOf(fmt) < 0) fmt = 'diagram';
  currentCanvasFormat = fmt;
  document.querySelectorAll('[data-canvas-view]').forEach(function(el) {
    el.hidden = el.dataset.canvasView !== fmt;
  });
  document.querySelectorAll('[data-canvas-format]').forEach(function(btn) {
    var on = btn.dataset.canvasFormat === fmt;
    btn.classList.toggle('is-active', on);
    btn.setAttribute('aria-pressed', on ? 'true' : 'false');
  });
  var zoomControls = document.getElementById('zoom-controls');
  if (zoomControls) zoomControls.hidden = fmt !== 'diagram';
  if (copyTextOutputBtn) {
    var label = fmt === 'diagram'
      ? 'Copy SVG markup'
      : 'Copy ' + (fmt === 'ascii' ? 'ASCII' : 'Unicode') + ' output';
    copyTextOutputBtn.title = label;
    copyTextOutputBtn.setAttribute('aria-label', label);
  }
  if (fmt !== 'diagram' && typeof ensureTextOutputs === 'function') ensureTextOutputs();
  if (fmt === 'unicode' && typeof fitUnicodeOutput === 'function') fitUnicodeOutput();
}

document.querySelectorAll('[data-canvas-format]').forEach(function(btn) {
  btn.addEventListener('click', function() { selectCanvasFormat(btn.dataset.canvasFormat); });
  btn.addEventListener('keydown', function(e) {
    if (!["ArrowLeft", "ArrowRight", "Home", "End"].includes(e.key)) return;
    e.preventDefault();
    var btns = Array.prototype.slice.call(document.querySelectorAll('[data-canvas-format]'));
    var i = btns.indexOf(btn);
    var n = e.key === 'Home' ? 0 : e.key === 'End' ? btns.length - 1
      : (i + (e.key === 'ArrowRight' ? 1 : -1) + btns.length) % btns.length;
    selectCanvasFormat(btns[n].dataset.canvasFormat);
    btns[n].focus();
  });
});

if (copyTextOutputBtn) copyTextOutputBtn.addEventListener('click', function() {
  if (currentCanvasFormat === 'diagram') {
    // Copy the rendered SVG markup — "Copy source" already lives in the export
    // dropdown, so the preview copy always copies what is on the canvas.
    var svgEl = previewInner.querySelector('svg');
    if (!svgEl) {
      setCopyFeedback(copyTextOutputBtn, 'err');
      showToast('Render a diagram before copying its SVG.');
      return;
    }
    writeClipboardText(new XMLSerializer().serializeToString(svgEl), 'SVG markup copied.', 'Copy SVG failed.', copyTextOutputBtn);
    return;
  }
  var el = document.getElementById(currentCanvasFormat + '-output');
  var name = currentCanvasFormat === 'ascii' ? 'ASCII' : 'Unicode';
  writeClipboardText(el ? el.textContent : '', name + ' output copied.', 'Copy ' + name + ' failed.', copyTextOutputBtn);
});

document.addEventListener('click', function(e) {
  var clearBtn = e.target.closest('[data-action="clear-editor"]');
  if (!clearBtn) return;
  clearEditor();
  if (typeof setExamplesSidebarOpen === 'function') setExamplesSidebarOpen(false);
});

// Keyboard-shortcut cheat sheet — same popup contract as the other popovers:
// inert + aria-hidden when closed, Escape closes, focus returns to the opener.
var shortcutsBtn = document.getElementById('shortcuts-btn');
var shortcutsDialog = document.getElementById('shortcuts-dialog');
var shortcutsDialogClose = document.getElementById('shortcuts-dialog-close');

var shortcutsPopup = (shortcutsBtn && shortcutsDialog && typeof createPopupController === 'function')
  ? createPopupController({
      popup: shortcutsDialog,
      trigger: shortcutsBtn,
      visibility: { manageTabStops: true, toggleTriggerClass: false },
      afterOpen: function() {
        if (shortcutsDialogClose) shortcutsDialogClose.focus();
      },
    })
  : null;

if (shortcutsDialogClose) shortcutsDialogClose.addEventListener('click', function() {
  if (shortcutsPopup) shortcutsPopup.close({ source: 'close-button', restoreFocus: true });
});

document.addEventListener('keydown', function(e) {
  if (e.key !== '?' || e.metaKey || e.ctrlKey || e.altKey || !shortcutsPopup) return;
  var target = e.target;
  var tag = target && target.tagName;
  // "?" is typed text inside the source editor and other fields; only treat it
  // as the cheat-sheet shortcut when focus is outside editable controls.
  if (tag === 'TEXTAREA' || tag === 'INPUT' || tag === 'SELECT' || (target && target.isContentEditable)) return;
  e.preventDefault();
  shortcutsPopup.open({ source: 'keyboard' });
});


var exportScale = 4;
var exportDropdown = document.getElementById('export-dropdown');
var exportMainBtn = document.getElementById('export-main-btn');
var exportChevronBtn = document.getElementById('export-chevron-btn');
var exportRequiresSvgButtons = [
  exportMainBtn,
  document.getElementById('export-png-btn'),
  document.getElementById('export-svg-btn'),
  document.getElementById('copy-png-btn'),
].filter(Boolean);

function hasRenderedSvg() {
  return previewInner.querySelector('svg') !== null;
}

function updateExportAvailability() {
  var enabled = hasRenderedSvg();
  exportRequiresSvgButtons.forEach(function(btn) {
    btn.disabled = !enabled;
    btn.setAttribute('aria-disabled', enabled ? 'false' : 'true');
  });
}

var exportPopup = createPopupController({
  popup: exportDropdown,
  trigger: exportChevronBtn,
  visibility: { toggleTriggerClass: false },
  beforeOpen: updateExportAvailability,
  afterOpen: function(meta) {
    if (meta && meta.focusFirst) {
      var first = exportDropdown.querySelector('button:not(:disabled)');
      if (first) first.focus();
    }
  },
  contains: function(target) { return !!target.closest('#export-wrap'); },
});

function setExportDropdownOpen(open, focusFirst) {
  exportPopup.setOpen(open, { focusFirst: !!focusFirst });
}

exportDropdown.querySelectorAll('button').forEach(function(btn) { btn.setAttribute('role', 'menuitem'); });
exportMainBtn.addEventListener('click', function() {
  exportPNG();
});

document.getElementById('size-pills').addEventListener('click', function(e) {
  var pill = e.target.closest('.size-pill');
  if (!pill) return;
  exportScale = parseInt(pill.dataset.scale, 10);
  document.querySelectorAll('.size-pill').forEach(function(p) {
    var on = p === pill;
    p.classList.toggle('active', on);
    p.setAttribute('aria-pressed', on ? 'true' : 'false');
  });
});

function getSvgEl() {
  var el = previewInner.querySelector('svg');
  if (!el) {
    showToast('Load or write a diagram before exporting.');
    updateExportAvailability();
    return null;
  }
  return el;
}

function serializeSvg(svgEl) {
  return new XMLSerializer().serializeToString(svgEl);
}

function svgToPngBlob(svgEl, scale, cb, onError) {
  var serialized = serializeSvg(svgEl);
  var svgBlob = new Blob([serialized], { type: 'image/svg+xml;charset=utf-8' });
  var url = URL.createObjectURL(svgBlob);
  var img = new Image();
  img.onload = function() {
    var canvas = document.createElement('canvas');
    var w = img.naturalWidth  || svgEl.viewBox.baseVal.width  || 800;
    var h = img.naturalHeight || svgEl.viewBox.baseVal.height || 600;
    canvas.width  = w * scale;
    canvas.height = h * scale;
    var ctx = canvas.getContext('2d');
    ctx.scale(scale, scale);
    ctx.drawImage(img, 0, 0);
    URL.revokeObjectURL(url);
    canvas.toBlob(cb, 'image/png');
  };
  img.onerror = function() {
    URL.revokeObjectURL(url);
    if (onError) onError();
    else showToast('PNG export failed.');
  };
  img.src = url;
}

function exportPNG() {
  var svgEl = getSvgEl(); if (!svgEl) return;
  svgToPngBlob(svgEl, exportScale, function(blob) {
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = 'diagram.png'; a.click();
    URL.revokeObjectURL(url);
    showToast('PNG saved (' + exportScale + '×).');
    setExportDropdownOpen(false, false);
  });
}

function exportSVG() {
  var svgEl = getSvgEl(); if (!svgEl) return;
  var data = serializeSvg(svgEl);
  var blob = new Blob([data], { type: 'image/svg+xml;charset=utf-8' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = 'diagram.svg'; a.click();
  URL.revokeObjectURL(url);
  showToast('SVG saved.');
  setExportDropdownOpen(false, false);
}

// Copy PNG hands the clipboard a promise immediately so the write stays
// inside the user-activation window while the PNG encodes off-thread.
var copyPngBtn = document.getElementById('copy-png-btn');

function copyPNG() {
  var svgEl = getSvgEl(); if (!svgEl) return;
  if (typeof ClipboardItem === 'undefined' || !navigator.clipboard || !navigator.clipboard.write) {
    setCopyFeedback(copyPngBtn, 'err');
    showToast('Copying images is not supported in this browser.');
    return;
  }
  var blobPromise = new Promise(function(resolve, reject) {
    svgToPngBlob(svgEl, exportScale, function(blob) {
      if (blob) resolve(blob);
      else reject(new Error('PNG encode failed'));
    }, function() { reject(new Error('PNG encode failed')); });
  });
  navigator.clipboard.write([new ClipboardItem({ 'image/png': blobPromise })]).then(function() {
    setCopyFeedback(copyPngBtn, 'ok');
    showToast('PNG copied (' + exportScale + '×).');
    setExportDropdownOpen(false, false);
  }).catch(function() {
    setCopyFeedback(copyPngBtn, 'err');
    showToast('Copy PNG failed.');
  });
}

function copyURL(sourceBtn) {
  // updateHash compresses asynchronously; wait so the copied URL is current.
  Promise.resolve(updateHash()).then(function() {
    writeClipboardText(window.location.href, 'Share link copied.', 'Copy link failed.', sourceBtn);
  });
}

var copyLinkBtn = document.getElementById('copy-link-btn');
var shareBtn = document.getElementById('share-btn');

document.getElementById('export-png-btn').addEventListener('click', exportPNG);
document.getElementById('export-svg-btn').addEventListener('click', exportSVG);
if (copyPngBtn) copyPngBtn.addEventListener('click', copyPNG);
copyLinkBtn.addEventListener('click', function() { copyURL(copyLinkBtn); });
if (shareBtn) shareBtn.addEventListener('click', function() { copyURL(shareBtn); });
updateExportAvailability();

document.addEventListener('keydown', function(e) {
  // Fires even while focus is in the source textarea — where users spend most
  // of their time — and preempts the browser's own Save dialog.
  if (!(e.metaKey || e.ctrlKey) || e.key.toLowerCase() !== 's') return;
  e.preventDefault();
  if (e.shiftKey) exportSVG();
  else exportPNG();
});


var isResizing = false;
var resizeStartX = 0;
var resizeStartW = 0;

function isNarrowViewport() {
  return window.matchMedia && window.matchMedia('(max-width: 760px)').matches;
}

function resizeBounds() {
  return {
    min: 280,
    max: Math.max(280, window.innerWidth * 0.75),
  };
}

function setPanelWidth(px) {
  if (isNarrowViewport()) {
    panelLeft.style.width = '';
    if (resizeHandle) resizeHandle.setAttribute('aria-disabled', 'true');
    return;
  }
  var bounds = resizeBounds();
  var newW = Math.max(bounds.min, Math.min(bounds.max, px));
  panelLeft.style.width = newW + 'px';
  if (resizeHandle) {
    resizeHandle.setAttribute('aria-disabled', 'false');
    resizeHandle.setAttribute('aria-valuemin', String(Math.round(bounds.min)));
    resizeHandle.setAttribute('aria-valuemax', String(Math.round(bounds.max)));
    resizeHandle.setAttribute('aria-valuenow', String(Math.round(newW)));
    resizeHandle.setAttribute('aria-valuetext', 'Source panel width ' + Math.round(newW) + ' pixels');
  }
}

function startResize(e) {
  isResizing = true;
  resizeStartX = e.clientX;
  resizeStartW = panelLeft.getBoundingClientRect().width;
  resizeHandle.classList.add('dragging');
  document.body.style.cursor = 'col-resize';
  document.body.style.userSelect = 'none';
  if (resizeHandle.setPointerCapture && e.pointerId != null) resizeHandle.setPointerCapture(e.pointerId);
}

function moveResize(e) {
  if (!isResizing) return;
  var dx = e.clientX - resizeStartX;
  setPanelWidth(resizeStartW + dx);
}

function endResize(e) {
  if (!isResizing) return;
  isResizing = false;
  resizeHandle.classList.remove('dragging');
  document.body.style.cursor = '';
  document.body.style.userSelect = '';
  if (resizeHandle.releasePointerCapture && e && e.pointerId != null) resizeHandle.releasePointerCapture(e.pointerId);
}

resizeHandle.addEventListener('pointerdown', function(e) {
  if (isNarrowViewport()) return;
  e.preventDefault();
  startResize(e);
});

document.addEventListener('pointermove', moveResize);
document.addEventListener('pointerup', endResize);
document.addEventListener('pointercancel', endResize);

resizeHandle.addEventListener('keydown', function(e) {
  if (isNarrowViewport()) return;
  var current = panelLeft.getBoundingClientRect().width;
  var bounds = resizeBounds();
  var next = current;
  if (e.key === 'ArrowLeft') next = current - (e.shiftKey ? 48 : 16);
  else if (e.key === 'ArrowRight') next = current + (e.shiftKey ? 48 : 16);
  else if (e.key === 'Home') next = bounds.min;
  else if (e.key === 'End') next = bounds.max;
  else return;
  e.preventDefault();
  setPanelWidth(next);
});

function syncResponsivePanelWidth() {
  if (isNarrowViewport()) {
    panelLeft.style.width = '';
    if (resizeHandle) resizeHandle.setAttribute('aria-disabled', 'true');
  } else {
    setPanelWidth(panelLeft.getBoundingClientRect().width || 420);
  }
}

if (typeof window !== 'undefined') window.addEventListener('resize', syncResponsivePanelWidth);
syncResponsivePanelWidth();


var toastTimer;
function showToast(msg) {
  toast.textContent = msg;
  toast.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(function() { toast.classList.remove('show'); }, 2500);
}


// A stored choice wins; with no stored preference the editor follows the OS
// (and keeps following it until the user toggles explicitly).
var darkSchemeQuery = window.matchMedia
  ? window.matchMedia("(prefers-color-scheme: dark)")
  : null;
var storedColorMode = localStorage.getItem("bm-editor-dark");
var isDark = storedColorMode === null
  ? !!(darkSchemeQuery && darkSchemeQuery.matches)
  : storedColorMode === "true";

var diagramThemeIsAuto = true;

function applyColorMode(dark, force) {
  isDark = dark;
  var darkLightBtn = document.getElementById("dark-light-btn");
  if (darkLightBtn) {
    darkLightBtn.classList.toggle("is-dark", dark);
    darkLightBtn.setAttribute("aria-label", dark ? "Switch to light mode" : "Switch to dark mode");
  }
  // Persist only explicit choices so a system-derived default keeps tracking
  // prefers-color-scheme instead of freezing on first load.
  if (force) localStorage.setItem("bm-editor-dark", dark ? "true" : "false");

  // Page chrome follows the Kiln brand (Stone/Charcoal + Pine). The diagram theme
  // is controlled separately by the dropdown so color mode does not silently
  // rewrite diagrams.
  applyThemeToPage(state.theme);
  // These may not exist yet during initial load – guarded calls
  if (typeof updateThemeButton === "function") updateThemeButton();
  if (typeof refreshAllColorUIs === "function") refreshAllColorUIs();
  if (typeof scheduleRender === "function") scheduleRender(0);
}

document
  .getElementById("dark-light-btn")
  .addEventListener("click", function () {
    applyColorMode(!isDark, true);
  });

if (darkSchemeQuery && typeof darkSchemeQuery.addEventListener === "function") {
  darkSchemeQuery.addEventListener("change", function (e) {
    if (localStorage.getItem("bm-editor-dark") === null) applyColorMode(e.matches);
  });
}


// Theme dropdown logic
var themeBtnLabel = document.getElementById("theme-btn-label");
var themeBtnSwatch = document.getElementById("theme-btn-swatch");
var themeDropdownBtn = document.getElementById("theme-dropdown-btn");

function updateThemeButton() {
  var key = state.theme;
  if (key && THEMES[key]) {
    themeBtnLabel.textContent =
      themeDropdownBtn.getAttribute("data-label-" + key) || key;
    themeBtnSwatch.style.background = THEMES[key].bg;
    themeBtnSwatch.style.display = "";
  } else {
    themeBtnLabel.textContent = "Default";
    // Keep the ringed swatch visible (CSS supplies a neutral fill) — on mobile
    // the swatch is the entire control, so hiding it left a blank button.
    themeBtnSwatch.style.background = "";
    themeBtnSwatch.style.display = "";
  }
  // Update active state in dropdown
  themeMenu.querySelectorAll(".theme-dropdown-item").forEach(function (item) {
    var active = item.dataset.theme === key;
    item.classList.toggle("active", active);
    item.setAttribute("aria-selected", active ? "true" : "false");
    item.tabIndex = themeMenu.classList.contains("open") && active ? 0 : -1;
  });
}

function setTheme(key) {
  state.theme = key;
  diagramThemeIsAuto = false;
  if (key) {
    localStorage.setItem("bm-editor-theme", key);
  } else {
    localStorage.removeItem("bm-editor-theme");
  }
  applyThemeToPage(key);
  updateThemeButton();
  refreshAllColorUIs();
  scheduleRender(0);
}

var themeMenuPopup = createPopupController({
  popup: themeMenu,
  trigger: themeDropdownBtn,
  visibility: { manageTabStops: false },
  afterOpen: function(meta) {
    syncThemeMenuTabStops(true);
    if (meta && meta.focusFirst) {
      var active = themeMenu.querySelector(".theme-dropdown-item.active") || themeMenu.querySelector(".theme-dropdown-item");
      if (active) active.focus();
    }
  },
  afterClose: function() { syncThemeMenuTabStops(false); },
  contains: function(target) { return !!target.closest("#theme-dropdown-wrap"); },
});

function syncThemeMenuTabStops(open) {
  themeMenu.querySelectorAll(".theme-dropdown-item").forEach(function(item) {
    var active = item.classList.contains("active");
    item.tabIndex = open && active ? 0 : -1;
  });
}

function setThemeMenuOpen(open, focusActive) {
  themeMenuPopup.setOpen(open, { focusFirst: !!focusActive });
}

// Click item
themeMenu.addEventListener("click", function (e) {
  var item = e.target.closest(".theme-dropdown-item");
  if (!item) return;
  setTheme(item.dataset.theme || "");
  setThemeMenuOpen(false, false);
  themeDropdownBtn.focus();
});

themeMenu.addEventListener("keydown", function(e) {
  var items = Array.prototype.slice.call(themeMenu.querySelectorAll(".theme-dropdown-item"));
  var current = document.activeElement && document.activeElement.classList.contains("theme-dropdown-item") ? document.activeElement : null;
  var index = Math.max(0, items.indexOf(current));
  if (["ArrowDown", "ArrowUp", "Home", "End"].includes(e.key)) {
    e.preventDefault();
    var next = index;
    if (e.key === "Home") next = 0;
    else if (e.key === "End") next = items.length - 1;
    else next = (index + (e.key === "ArrowDown" ? 1 : -1) + items.length) % items.length;
    items[next].tabIndex = 0;
    items[next].focus();
  }
  if (e.key === "Enter" || e.key === " ") {
    e.preventDefault();
    if (current) current.click();
  }
});

// Store label data for lookup
themeMenu.querySelectorAll(".theme-dropdown-item").forEach(function (item) {
  var key = item.dataset.theme || "";
  themeDropdownBtn.setAttribute("data-label-" + key, item.textContent.trim());
});

// Apply initial dark/light mode (must happen after all DOM refs + functions are ready)
applyColorMode(isDark);

// Restore saved theme, otherwise start on the brand Paper theme so the editor
// opens with the same diagram palette the public site renders.
var savedTheme = localStorage.getItem("bm-editor-theme") || "";
if (savedTheme && THEMES[savedTheme]) {
  state.theme = savedTheme;
  diagramThemeIsAuto = false;
} else if (!state.theme || !THEMES[state.theme]) {
  state.theme = DEFAULT_EDITOR_THEME;
  diagramThemeIsAuto = true;
}
applyThemeToPage(state.theme);
updateThemeButton();
setThemeMenuOpen(false, false);

// ── Style dropdown (the LOOK — hand-drawn, watercolor, …) ───────────────────
// Mirrors the theme dropdown: style picks the mark treatment, theme picks the
// palette; buildOptions stacks them (theme colors win by render precedence).
var styleBtnLabel = document.getElementById("style-btn-label");
var styleDropdownBtn = document.getElementById("style-dropdown-btn");
var styleMenu = document.getElementById("style-dropdown-menu");
var seedShuffleBtn = document.getElementById("seed-shuffle-btn");

function updateStyleButton() {
  var key = state.style || "crisp";
  styleBtnLabel.textContent =
    styleDropdownBtn.getAttribute("data-label-" + key) || key;
  styleMenu.querySelectorAll(".theme-dropdown-item").forEach(function (item) {
    var active = (item.dataset.style || "crisp") === key;
    item.classList.toggle("active", active);
    item.setAttribute("aria-selected", active ? "true" : "false");
    item.tabIndex = styleMenu.classList.contains("open") && active ? 0 : -1;
  });
  // The ink seed only means something for a styled look.
  if (seedShuffleBtn) seedShuffleBtn.hidden = key === "crisp";
}

function setStyle(key) {
  state.style = key || "crisp";
  if (state.style !== "crisp") {
    localStorage.setItem("bm-editor-style", state.style);
  } else {
    localStorage.removeItem("bm-editor-style");
  }
  updateStyleButton();
  scheduleRender(0);
}

var styleMenuPopup = createPopupController({
  popup: styleMenu,
  trigger: styleDropdownBtn,
  visibility: { manageTabStops: false },
  afterOpen: function(meta) {
    syncStyleMenuTabStops(true);
    if (meta && meta.focusFirst) {
      var active = styleMenu.querySelector(".theme-dropdown-item.active") || styleMenu.querySelector(".theme-dropdown-item");
      if (active) active.focus();
    }
  },
  afterClose: function() { syncStyleMenuTabStops(false); },
  contains: function(target) { return !!target.closest("#style-dropdown-wrap"); },
});

function syncStyleMenuTabStops(open) {
  styleMenu.querySelectorAll(".theme-dropdown-item").forEach(function(item) {
    var active = item.classList.contains("active");
    item.tabIndex = open && active ? 0 : -1;
  });
}

function setStyleMenuOpen(open, focusActive) {
  styleMenuPopup.setOpen(open, { focusFirst: !!focusActive });
}

styleMenu.addEventListener("click", function (e) {
  var item = e.target.closest(".theme-dropdown-item");
  if (!item) return;
  setStyle(item.dataset.style || "crisp");
  setStyleMenuOpen(false, false);
  styleDropdownBtn.focus();
});

styleMenu.addEventListener("keydown", function(e) {
  var items = Array.prototype.slice.call(styleMenu.querySelectorAll(".theme-dropdown-item"));
  var current = document.activeElement && document.activeElement.classList.contains("theme-dropdown-item") ? document.activeElement : null;
  var index = Math.max(0, items.indexOf(current));
  if (["ArrowDown", "ArrowUp", "Home", "End"].includes(e.key)) {
    e.preventDefault();
    var next = index;
    if (e.key === "Home") next = 0;
    else if (e.key === "End") next = items.length - 1;
    else next = (index + (e.key === "ArrowDown" ? 1 : -1) + items.length) % items.length;
    items[next].tabIndex = 0;
    items[next].focus();
  }
  if (e.key === "Enter" || e.key === " ") {
    e.preventDefault();
    if (current) current.click();
  }
});

styleMenu.querySelectorAll(".theme-dropdown-item").forEach(function (item) {
  var key = item.dataset.style || "crisp";
  styleDropdownBtn.setAttribute("data-label-" + key, item.textContent.trim());
});

if (seedShuffleBtn) {
  seedShuffleBtn.addEventListener("click", function () {
    // Deterministic walk, not random: the same clicks reproduce the same ink.
    state.seed = (state.seed | 0) + 1;
    scheduleRender(0);
    if (typeof scheduleDraftSave === 'function') scheduleDraftSave();
  });
}

var savedStyle = localStorage.getItem("bm-editor-style") || "";
if (savedStyle) state.style = savedStyle;
updateStyleButton();
setStyleMenuOpen(false, false);

// Load from URL hash or start on an on-brand default so the editor opens with
// the loop already working (a rendered diagram, verify results, and on-demand
// text outputs) instead of five empty states. The default is the product's own
// parse -> verify -> serialize loop.
var DEFAULT_SOURCE = [
  "flowchart TD",
  "  A[Parse source] --> B[Narrow intent]",
  "  B --> C[Mutate one node]",
  "  C --> D{Verify}",
  "  D -- ok --> E[Serialize]",
  "  D -- warnings --> B",
].join("\n");

// Draft restore notice: polite, transient, with an explicit way to discard.
var draftNotice = document.getElementById("draft-notice");
var draftDiscardBtn = document.getElementById("draft-discard-btn");
var draftNoticeTimer = null;

function hideDraftNotice() {
  if (draftNoticeTimer) clearTimeout(draftNoticeTimer);
  draftNoticeTimer = null;
  if (draftNotice) draftNotice.hidden = true;
}

function showDraftRestoredNotice() {
  if (!draftNotice) return;
  draftNotice.hidden = false;
  if (draftNoticeTimer) clearTimeout(draftNoticeTimer);
  draftNoticeTimer = setTimeout(hideDraftNotice, 8000);
}

function discardRestoredDraft() {
  if (typeof discardEditorDraft === "function") discardEditorDraft();
  hideDraftNotice();
  editor.value = DEFAULT_SOURCE;
  state.config = {};
  setEditorErrorLine(0);
  refreshAllColorUIs();
  updateLineNumbers();
  updateCursorPos();
  scheduleRender(0);
  showToast("Draft discarded.");
}

if (draftDiscardBtn) draftDiscardBtn.addEventListener("click", discardRestoredDraft);

function shouldOpenEmptyEditor() {
  try {
    var value = new URLSearchParams(window.location.search).get('empty');
    return value === '1' || value === 'true';
  } catch(e) { return false; }
}

// getHashSource decodes compressed share links asynchronously, so the initial
// source pick runs in an async IIFE; nothing below in this file depends on it.
(async function initializeEditorSource() {
  var hashSource = await getHashSource();
  // A share link that exists but cannot be decoded must say so — silently
  // showing the recipient their old draft or the default diagram would let
  // them believe they are looking at what was shared.
  if (!hashSource && typeof hashDecodeFailure === 'string' && hashDecodeFailure && typeof showToast === 'function') {
    showToast(hashDecodeFailure === 'unsupported'
      ? 'This share link needs a newer browser to open (missing DecompressionStream). Showing your own content instead.'
      : 'This share link could not be decoded (truncated or damaged). Showing your own content instead.');
  }
  var queryExampleId = getQueryExampleId();
  var queryEmptyEditor = shouldOpenEmptyEditor();
  var loadedInitialExample = false;
  if (hashSource) {
    editor.value = hashSource;
    applyThemeToPage(state.theme);
    updateThemeButton();
    refreshAllColorUIs();
  } else if (queryExampleId && typeof loadEditorExample === 'function' && findEditorExample(queryExampleId)) {
    loadEditorExample(queryExampleId);
    loadedInitialExample = true;
  } else if (queryEmptyEditor) {
    editor.value = '';
    state.config = {};
    refreshAllColorUIs();
  } else {
    // No shared source or explicit blank-start request in the URL: restore the autosaved draft if one exists.
    var draft = typeof readEditorDraft === 'function' ? readEditorDraft() : null;
    if (draft) {
      editor.value = draft.source;
      if (hasOwnConfig(draft.config)) state.config = draft.config;
      if (draft.style) state.style = draft.style;
      if (typeof draft.seed === 'number') state.seed = draft.seed;
      refreshAllColorUIs();
      showDraftRestoredNotice();
      // A restored draft means a returning editor: on mobile, put Source (and
      // the draft notice) back on screen instead of the first-run Preview.
      if (typeof setMobilePanel === 'function' && document.body.dataset.mobilePanel === 'preview') {
        setMobilePanel('code');
      }
    } else {
      editor.value = DEFAULT_SOURCE;
    }
  }

  if (!loadedInitialExample) {
    updateLineNumbers();
    scheduleRender(0);
  }
})();
